ild(link);    link.click();    document.body.removeChild(link);});// PDF export using html2canvas + jsPDF (ensure background white and useCORS)document.getElementById('btnExportPDF').addEventListener('click', function(){    const element = document.getElementById('temperature-table');    if(!element){        alert('No table found');        return;    }    html2canvas(element, {        scale: 2,        backgroundColor: '#ffffff'    }).then(canvas => {        const imgData = canvas.toDataURL('image/jpeg', 1.0);        const { jsPDF } = window.jspdf;        const pdf = new jsPDF({            orientation: 'landscape',            unit: 'px',            format: 'a4'        });        const pageWidth = pdf.internal.pageSize.getWidth();        const pageHeight = pdf.internal.pageSize.getHeight();        const imgWidth = pageWidth - 20;        const imgHeight = (canvas.height * imgWidth) / canvas.width;        pdf.addImage(imgData, 'JPEG', 10, 10, imgWidth, imgHeight);        pdf.save('temperature_report.pdf');    }).catch(error => {        console.error(error);        alert("PDF generation failed");    });});</script></body>	</html>		